@font-face {
  font-family: 'Inter';
  src: url('/fonts/inter-v3-latin-regular.woff2') format('woff2'),
       url('/fonts/inter-v3-latin-regular.woff') format('woff');
  font-weight: 400;
  font-style: normal;
  font-display: swap; /* Ensures immediate text visibility with a fallback */
}

body {
  font-family: 'Inter', sans-serif;
  line-height: 1.6;
  font-size: 18px;
}
